text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      "공개 릴리스 목표는 스모크 테스트가 통과할 경우 금요일 15:00 KST로 정했다.",
      "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트(s moke-theme-pack.mjs)를 검토하기로 했다."
    ],
    "rejected_proposals": [
      "Hara의 제안인 smoke-theme-pack.mjs에서 packageName 불일치를 무시하는 변경은 거부되었다."
    ],
    "internal_stretch_goals": [
      "수요일 공개 릴리스를 제안했으나 최종 결정은 아니며 내부 스트레치 목표로만 남았다.",
      "README 설치 절차는 가능하면 목요일까지 검토하자는 의견이 있었으나, 담당자와 확정 일정은 정해지지 않았다."
    ],
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 절차가 오래되었으면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한은 누구에게 있는가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 여부는 무엇인가?"
    ],
    "non_decisions": [
      "고객명이나 외부 파트너명은 특정되지 않았다.",
      "수요일 릴리스 제안은 확정되지 않았다.",
      "README 설치 절차 검토는 필요성이 언급되었지만 담당자와 확정 마감은 정해지지 않았다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed from fixture"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed from fixture"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "unspecified",
      "status": "confirmed",
      "source_certainty": "confirmed from fixture"
    }
  ],
  "followup_note": "다음 확인 대상은 스모크 테스트 결과, tarball 경로, 그리고 최종 릴리스 승인 권한이다. README 설치 절차의 최신성도 점검하되, 고객명, 예산, 보안 사고, 운영 장애, 법무 승인, 소유자, 확정되지 않은 마감일은 새로 만들지 말아야 한다.",
  "non_invention_rules": [
    "고객명 또는 외부 파트너명을 추정하지 않는다.",
    "예산, 보안 사고, 생산 장애, 법무 승인 요구사항을 추가하지 않는다.",
    "최종 승인자, 미지정 소유자, 확정되지 않은 마감일을 임의로 채우지 않는다.",
    "fixture에 없는 일정이나 결과를 사실처럼 쓰지 않는다.",
    "내부 스트레치 목표는 확정 결정과 분리해서 기록한다."
  ]
}
